1	type Item = {
2	  type: string;
3	  material?: string;
4	  cursed?: boolean;
5	  enchantment?: number;
6	};
7	
8	type Customer = { yearsWithMHPCO: number };
9	
10	type QuoteStep = { op: "quote"; items: Item[] };
11	
12	type Damage = { itemType: string; amount: number };
13	
14	type ClaimStep = {
15	  op: "claim";
16	  policy: number;
17	  incident: { cause: string; damages: Damage[] };
18	};
19	
20	type Step = QuoteStep | ClaimStep;
21	
22	type Scenario = {
23	  customer: Customer;
24	  steps: Step[];
25	};
26	
27	type ScenarioResult = {
28	  results: { premium?: number; payout?: number; remainingCap?: number }[];
29	};
30	
31	const PROCESSING_FEE = 5;
32	
33	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
34	
35	const firstInsuranceSurcharge = (premium: number): number =>
36	  premium * FIRST_INSURANCE_SURCHARGE_RATE;
37	
38	const COMPONENT_PREMIUM = 25;
39	
40	const BASE_PREMIUMS: Record<string, number> = {
41	  sword: 100,
42	  amulet: 60,
43	  staff: 80,
44	  potion: 40,
45	  rune: COMPONENT_PREMIUM,
46	  moonstone: COMPONENT_PREMIUM,
47	};
48	
49	const BLOCK_PREMIUM = 60;
50	
51	const isBlock = (count: number): boolean => count === 3;
52	
53	const countByType = (items: Item[]): Record<string, number> =>
54	  items.reduce<Record<string, number>>((counts, item) => {
55	    counts[item.type] = (counts[item.type] ?? 0) + 1;
56	    return counts;
57	  }, {});
58	
59	const premiumForGroup = (type: string, count: number): number =>
60	  isBlock(count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
61	
62	const basePremiumFor = (items: Item[]): number =>
63	  Object.entries(countByType(items)).reduce(
64	    (total, [type, count]) => total + premiumForGroup(type, count),
65	    0,
66	  );
67	
68	const roundUpToWholeGold = (amount: number): number => Math.ceil(amount);
69	
70	const roundDownToWholeGold = (amount: number): number => Math.floor(amount);
71	
72	const sumBy = (items: Item[], valueOf: (item: Item) => number): number =>
73	  items.reduce((total, item) => total + valueOf(item), 0);
74	
75	const surchargeFor = (
76	  items: Item[],
77	  qualifies: (item: Item) => boolean,
78	  rate: number,
79	): number =>
80	  sumBy(items, (item) =>
81	    qualifies(item) ? BASE_PREMIUMS[item.type] * rate : 0,
82	  );
83	
84	const CURSE_SURCHARGE_RATE = 0.5;
85	
86	const isCursed = (item: Item): boolean => item.cursed === true;
87	
88	const curseSurchargeFor = (items: Item[]): number =>
89	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
90	
91	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
92	
93	const ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
94	
95	const isHighlyEnchanted = (item: Item): boolean =>
96	  (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD;
97	
98	const enchantmentSurchargeFor = (items: Item[]): number =>
99	  surchargeFor(items, isHighlyEnchanted, ENCHANTMENT_SURCHARGE_RATE);
100	
101	const discountFor = (
102	  qualifies: boolean,
103	  premium: number,
104	  rate: number,
105	): number => (qualifies ? premium * rate : 0);
106	
107	const LOYALTY_DISCOUNT_RATE = 0.2;
108	
109	const LOYALTY_YEARS_THRESHOLD = 2;
110	
111	const loyaltyDiscountFor = (customer: Customer, premium: number): number =>
112	  discountFor(
113	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
114	    premium,
115	    LOYALTY_DISCOUNT_RATE,
116	  );
117	
118	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
119	
120	const followUpDiscountFor = (isFollowUp: boolean, premium: number): number =>
121	  discountFor(isFollowUp, premium, FOLLOW_UP_DISCOUNT_RATE);
122	
123	const isKnownItemType = (item: Item): boolean => item.type in BASE_PREMIUMS;
124	
125	const assertKnownItemTypes = (items: Item[]): void => {
126	  for (const item of items) {
127	    if (!isKnownItemType(item)) {
128	      throw new Error(`Unknown item type: ${item.type}`);
129	    }
130	  }
131	};
132	
133	const quotePremium = (
134	  customer: Customer,
135	  items: Item[],
136	  isFollowUp: boolean,
137	): number => {
138	  assertKnownItemTypes(items);
139	  const basePremium = basePremiumFor(items);
140	  return roundUpToWholeGold(
141	    basePremium +
142	      curseSurchargeFor(items) +
143	      enchantmentSurchargeFor(items) +
144	      firstInsuranceSurcharge(basePremium) -
145	      loyaltyDiscountFor(customer, basePremium) -
146	      followUpDiscountFor(isFollowUp, basePremium) +
147	      PROCESSING_FEE,
148	  );
149	};
150	
151	const DEDUCTIBLE = 100;
152	
153	const HIGH_ENCHANTMENT_THRESHOLD = 8;
154	
155	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
156	
157	const reimbursementRateFor = (item: Item | undefined): number =>
158	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
159	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
160	    : 1;
161	
162	const payoutForDamage = (insuredItems: Item[], damage: Damage): number => {
163	  const insuredItem = insuredItems.find(
164	    (item) => item.type === damage.itemType,
165	  );
166	  return damage.amount * reimbursementRateFor(insuredItem) - DEDUCTIBLE;
167	};
168	
169	const insuredItemsForPolicy = (steps: Step[], policy: number): Item[] => {
170	  const policyStep = steps[policy];
171	  return policyStep.op === "quote" ? policyStep.items : [];
172	};
173	
174	const assertDamagesCoveredByPolicy = (
175	  insuredItems: Item[],
176	  damages: Damage[],
177	): void => {
178	  for (const damage of damages) {
179	    if (!insuredItems.some((item) => item.type === damage.itemType)) {
180	      throw new Error(`Item type not in policy: ${damage.itemType}`);
181	    }
182	  }
183	};
184	
185	const claimPayout = (insuredItems: Item[], damages: Damage[]): number =>
186	  damages.reduce(
187	    (total, damage) => total + payoutForDamage(insuredItems, damage),
188	    0,
189	  );
190	
191	const INSURANCE_VALUES: Record<string, number> = {
192	  sword: 1000,
193	  amulet: 600,
194	  rune: 250,
195	};
196	
197	const CAP_MULTIPLIER = 2;
198	
199	const insuranceSumFor = (items: Item[]): number =>
200	  sumBy(items, (item) => INSURANCE_VALUES[item.type]);
201	
202	const remainingCapFor = (insuredItems: Item[], totalPaid: number): number =>
203	  CAP_MULTIPLIER * insuranceSumFor(insuredItems) - totalPaid;
204	
205	const claimResult = (
206	  steps: Step[],
207	  step: ClaimStep,
208	  alreadyPaid: number,
209	): { payout: number; remainingCap: number } => {
210	  const insuredItems = insuredItemsForPolicy(steps, step.policy);
211	  assertDamagesCoveredByPolicy(insuredItems, step.incident.damages);
212	  const remainingCap = remainingCapFor(insuredItems, alreadyPaid);
213	  const payout = roundDownToWholeGold(
214	    Math.min(claimPayout(insuredItems, step.incident.damages), remainingCap),
215	  );
216	  return { payout, remainingCap: remainingCap - payout };
217	};
218	
219	export const runScenario = (scenario: Scenario): ScenarioResult => {
220	  const paidByPolicy: Record<number, number> = {};
221	  return {
222	    results: scenario.steps.map((step, index) => {
223	      if (step.op === "quote") {
224	        return {
225	          premium: quotePremium(scenario.customer, step.items, index > 0),
226	        };
227	      }
228	      const alreadyPaid = paidByPolicy[step.policy] ?? 0;
229	      const result = claimResult(scenario.steps, step, alreadyPaid);
230	      paidByPolicy[step.policy] = alreadyPaid + result.payout;
231	      return result;
232	    }),
233	  };
234	};
